defmodule MyPhoenixAppWeb.WebhookProxyController do
  use MyPhoenixAppWeb, :controller
  alias HTTPoison

  def fetch_content(conn, %{"url" => url}) do
    case HTTPoison.get(url) do
      {:ok, response} ->
        json = Poison.decode!(response.body)
